import{_ as i,c as a,o as e,ag as t}from"./chunks/framework.DPDPlp3K.js";const r="/assets/2025-01-04-17-07-33.DP8FZRiA.png",x=JSON.parse('{"title":"基础知识","description":"","frontmatter":{},"headers":[],"relativePath":"计算机/通识/存储.md","filePath":"计算机/通识/存储.md","lastUpdated":null}'),o={name:"计算机/通识/存储.md"};function s(n,l,u,h,d,c){return e(),a("div",null,l[0]||(l[0]=[t('<h1 id="基础知识" tabindex="-1">基础知识 <a class="header-anchor" href="#基础知识" aria-label="Permalink to &quot;基础知识&quot;">​</a></h1><ul><li>硬盘的基本存储单位: <strong>扇区</strong>(sector), 一个 sector 一般 512 Byte(字节)~4096 Byte</li><li>现在市售的SSD硬盘, 扇区多为4KB</li><li>4K对齐是一种硬盘分区技术, 4K指的是物理扇区大小为4KB(4096Byte)的硬盘, 对齐时确保硬盘的逻辑分区与物理扇区对齐, 从而提高读写效率. <ul><li>现代操作系统在格式化硬盘时通常会默认进行4K对齐, 手动对齐需要专业的软件工具</li><li><img src="'+r+'" alt=""></li></ul></li><li><strong>簇</strong>(block)=几个连续的 sector, 常见有4KB, 8KB, 16KB</li><li>文件存储时占用的空间以簇为单位分配, 因此文件真实大小 &lt;= 文件占用空间</li><li>一些很小的文件不会&quot;占用空间&quot;, 是因为和文件元信息存储在了一起. <ul><li><a href="https://learn.microsoft.com/zh-cn/windows/win32/devnotes/master-file-table" target="_blank" rel="noreferrer">主文件表 (MFT)</a></li></ul></li><li>簇的使用提高了存储效率, 但簇越大存储空间的浪费越明显, 在格式化硬盘时可以选择簇, 一般保持默认即可</li></ul><h2 id="分区表" tabindex="-1">分区表 <a class="header-anchor" href="#分区表" aria-label="Permalink to &quot;分区表&quot;">​</a></h2><ul><li>磁盘的分区表是存储在磁盘上的一种数据结构，用于记录磁盘的分区信息，如分区的起始位置、结束位置、分区类型等。</li><li>像是磁盘的 “地图”，告诉操作系统磁盘是如何划分的，以及每个分区在磁盘中的位置，让操作系统能够正确地识别和访问各个分区。</li><li>常见的磁盘分区表类型有 MBR 和 GPT</li></ul><h3 id="gtp" tabindex="-1">GTP <a class="header-anchor" href="#gtp" aria-label="Permalink to &quot;GTP&quot;">​</a></h3><ul><li>GPT（GUID Partition Table）, 全局唯一标识分区表, <strong>是EFI标准的一部分</strong>，旨在克服MBR的限制，适用于现代硬盘和UEFI系统。</li><li>GPT可以管理超过2TB的硬盘空间，理论上最大支持18EB（18 exabytes），远超MBR的限制</li><li>GPT将分区信息分散存储在硬盘的多个位置，而不是集中在第一个扇区，这提高了数据的安全性和可靠性</li></ul><h3 id="mbr" tabindex="-1">MBR <a class="header-anchor" href="#mbr" aria-label="Permalink to &quot;MBR&quot;">​</a></h3><ul><li>MBR（Master Boot Record）, 主引导记录, 是较早出现的分区表格式，起源于MS-DOS时代</li><li>MBR无法管理超过2TB（2048GB）的硬盘空间，因此对于大容量硬盘的支持较差</li><li>MBR将分区表存储在硬盘的第一个扇区（通常称为引导扇区），该扇区还包含引导加载程序</li><li>MBR格式与传统的BIOS系统兼容，<strong>但不支持UEFI启动</strong></li></ul><h2 id="文件系统" tabindex="-1">文件系统 <a class="header-anchor" href="#文件系统" aria-label="Permalink to &quot;文件系统&quot;">​</a></h2><ul><li>磁盘的文件系统是在磁盘分区的基础上，用于组织、管理和存储文件及目录的逻辑结构。</li><li>每个分区都对应一个独立的文件系统。一个硬盘可以有多个分区，每个分区可以使用不同的文件系统.</li><li>是操作系统用于管理存储设备上数据的一种机制, 是组织和存储文件的逻辑方式</li><li>将磁盘空间划分为多个逻辑区域，并通过目录结构组织这些区域中的文件和数据</li><li>允许用户以文件的形式存储和访问数据，而无需关心底层硬件的具体细节</li></ul><h3 id="btrfs" tabindex="-1">btrfs <a class="header-anchor" href="#btrfs" aria-label="Permalink to &quot;btrfs&quot;">​</a></h3><ul><li>Btrfs（B-Tree文件系统）是一种由Oracle公司于2007年开发的新型文件系统，旨在取代Linux上的ext3和ext4文件系统</li><li>在Linux系统中，可以通过安装<code>btrfs-progs</code>软件包来获取创建和管理Btrfs文件系统</li><li>在Windows系统中，可以通过安装<code>WinBtrfs</code>程序来获取创建和管理Btrfs文件系统</li></ul><h3 id="ntfs" tabindex="-1">ntfs <a class="header-anchor" href="#ntfs" aria-label="Permalink to &quot;ntfs&quot;">​</a></h3><ul><li>NTFS（New Technology File System） ：Windows系统中广泛使用的文件系统，支持大容量存储和高级功能。</li><li>在Linux系统中，可以通过安装<code>ntfs-3g</code>工具实现读写支持</li></ul><h3 id="ext" tabindex="-1">ext <a class="header-anchor" href="#ext" aria-label="Permalink to &quot;ext&quot;">​</a></h3><ul><li>ext是Linux系统中常用的文件系统，具有高性能和高可靠性。</li><li>具有多个版本的演进: ext, ext2, ext3, ext4(目前最常用)</li></ul><h3 id="fat" tabindex="-1">FAT <a class="header-anchor" href="#fat" aria-label="Permalink to &quot;FAT&quot;">​</a></h3><ul><li>FAT（File Allocation Table） ：早期的文件系统，适用于小容量存储设备(U盘, SD卡)</li><li>包括FAT, FAT16, FAT32三种, 前两者几乎已经淘汰</li><li>FAT32支持单个文件最大4GB</li><li>FAT32 是Linux和windows均原生支持的文件系统.</li></ul><h3 id="exfat" tabindex="-1">exFAT <a class="header-anchor" href="#exfat" aria-label="Permalink to &quot;exFAT&quot;">​</a></h3><ul><li>exFAT是FAT32的改进版本, 支持大文件(16EB)</li><li>Windows原生支持</li><li>在Linux系统中，需要安装<code>exfat-utils</code>工具</li></ul><h3 id="其他文件系统" tabindex="-1">其他文件系统 <a class="header-anchor" href="#其他文件系统" aria-label="Permalink to &quot;其他文件系统&quot;">​</a></h3><ul><li>HFS+（Hierarchical File System Plus） ：苹果macOS系统默认使用的文件系统。</li><li>XFS：高性能的日志型文件系统，适用于大规模数据存储</li></ul>',22)]))}const b=i(o,[["render",s]]);export{x as __pageData,b as default};
